// Extract request data and merge with config
const input = $input.first().json;
const config = input.config;
const data = input.request?.body || input.request || {};

// UUID v4 generator (n8n Code node sandbox doesn't have crypto global)
function generateUUID() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const question = data.question || data.chatInput || '';
const familyId = data.family_id;
const userId = data.user_id;
const paperlessUsername = data.paperless_username;
const conversationId = data.conversation_id || null;
const correlationId = data.correlation_id || generateUUID();
const clientIp = data.client_ip || null;
const userAgent = data.user_agent || null;

if (!question) {
  throw new Error('No question provided');
}

if (!familyId) {
  throw new Error('No family_id provided - please select a family first');
}

if (!userId) {
  throw new Error('No user_id provided');
}

// Generate title from question for new conversations
const title = question.length > 50 ? question.substring(0, 50) + '...' : question;

return [{
  json: {
    config,
    question,
    family_id: familyId,
    user_id: userId,
    paperless_username: paperlessUsername,
    conversation_id: conversationId,
    correlation_id: correlationId,
    client_ip: clientIp,
    user_agent: userAgent,
    conversation_title: title,
    request_start_time: Date.now()
  }
}];

// Merge conversation ID back into data
const inputData = $('Extract Input').first().json;
const convResult = $input.first().json;

return [{
  json: {
    ...inputData,
    conversation_id: convResult.id,
    is_new_conversation: convResult.source === 'new'
  }
}];

// Get chat history for context
const inputData = $('Merge Conversation ID').first().json;
const userMsgResult = $input.first().json;

return [{
  json: {
    ...inputData,
    user_message_id: userMsgResult.id
  }
}];

// Format chat history and prepare for RAG
const inputData = $('After User Save').first().json;
const historyResult = $input.first().json;

// Parse the JSON array from the Postgres query
// The query returns: { history: [{role, content}, ...] } or { history: [] }
let chatHistory = [];
if (historyResult && historyResult.history) {
  chatHistory = Array.isArray(historyResult.history) 
    ? historyResult.history.map(row => ({ role: row.role, content: row.content }))
    : [];
}

return [{
  json: {
    ...inputData,
    chat_history: chatHistory
  }
}];

// Generate sparse vector for BM25
function hashCode(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash) + str.charCodeAt(i);
    hash = hash & hash;
  }
  return Math.abs(hash);
}

const inputData = $('Format History').first().json;
const embedding = $input.first().json.embedding;

const words = inputData.question.toLowerCase().split(/\W+/).filter(w => w.length > 2);
const wordCounts = {};
words.forEach(w => { wordCounts[w] = (wordCounts[w] || 0) + 1; });

const indices = [], values = [];
Object.entries(wordCounts).forEach(([word, count]) => {
  indices.push(hashCode(word) % 30000);
  values.push(count);
});

return [{ json: {
  ...inputData,
  dense_vector: embedding,
  sparse_vector: { indices, values }
}}];

const prevData = $('Prepare Vectors').first().json;
const searchResponse = $input.first().json;
const results = searchResponse.result?.points || [];

return [{ json: {
  ...prevData,
  result: results,
  result_count: results.length
}}];

const inputData = $input.first().json;
const familyId = inputData.family_id;
const familyName = familyId.charAt(0).toUpperCase() + familyId.slice(1);

return [{ json: {
  ...inputData,
  response_text: `I couldn't find any relevant documents for your question in the ${familyName} family files. Please make sure documents have been indexed for this family, or try rephrasing your question.`,
  citations: [],
  documents_retrieved: []
}}];

// Keyword boosting with query expansion
const inputData = $input.first().json;
const question = inputData.question.toLowerCase();
const results = inputData.result || [];
const config = inputData.config;

const expansions = {
  'married': ['marriage', 'spouse', 'wedding', 'wife', 'husband', 'divorced', 'divorce', 'separated'],
  'marriage': ['married', 'spouse', 'wedding', 'wife', 'husband', 'divorced', 'divorce'],
  'divorce': ['divorced', 'separated', 'marriage', 'married', 'spouse', 'ex-wife', 'ex-husband'],
  'children': ['child', 'son', 'daughter', 'kids', 'offspring', 'minor'],
  'death': ['died', 'deceased', 'passed', 'dead', 'obituary'],
  'trust': ['trustee', 'beneficiary', 'estate', 'will', 'inheritance'],
  'property': ['real estate', 'house', 'home', 'land', 'deed', 'asset'],
  'money': ['funds', 'assets', 'account', 'bank', 'investment', 'financial'],
  'events': ['timeline', 'history', 'dates', 'occurred', 'happened', 'key']
};

const questionWords = question.split(/\W+/).filter(w => w.length > 3);
const expandedWords = new Set(questionWords);
for (const word of questionWords) {
  if (expansions[word]) {
    expansions[word].forEach(related => expandedWords.add(related));
  }
}
const allSearchTerms = Array.from(expandedWords);

const scored = results.map(result => {
  const text = (result.payload.text || '').toLowerCase();
  const contextText = (result.payload.context_text || '').toLowerCase();
  const docTitle = (result.payload.document_title || '').toLowerCase();

  let keywordScore = 0;
  for (const word of allSearchTerms) {
    if (text.includes(word)) keywordScore += 0.2;
    if (contextText.includes(word)) keywordScore += 0.1;
    if (docTitle.includes(word)) keywordScore += 0.1;
  }
  keywordScore += result.score * 0.15;

  return {
    id: result.id,
    rrf_score: result.score,
    keyword_score: keywordScore,
    title: result.payload.document_title || 'Unknown',
    text: result.payload.text || '',
    context_text: result.payload.context_text || '',
    page_num: result.payload.page_num || 1,
    payload: result.payload
  };
});

const prefilterTopK = config.PREFILTER_TOP_K || 25;
const candidates = scored.sort((a, b) => b.keyword_score - a.keyword_score).slice(0, prefilterTopK);

return [{ json: {
  ...inputData,
  candidates,
  documents_retrieved: scored.map(r => ({ id: r.id, title: r.title, page_num: r.page_num, rrf_score: r.rrf_score, document_id: r.payload?.document_id }))
}}];

// Pointwise 0-10 Reranker
const inputData = $input.first().json;
const { config, question, candidates } = inputData;

if (!candidates || candidates.length === 0) {
  return [{ json: { ...inputData, top_results: [] }}];
}

const MODEL_NAME = config.RERANKER_MODEL;
const OLLAMA_URL = config.OLLAMA_URL;
const TOP_K = config.RERANKER_TOP_K || 10;
const MIN_SCORE = config.RERANKER_MIN_SCORE || 2.0;

const httpRequest = this.helpers.httpRequest.bind(this.helpers);

const scorePromises = candidates.map(async (doc) => {
  const textPreview = (doc.text || '').substring(0, 800).replace(/\n/g, ' ');
  const prompt = `Task: Rate the relevance of the following document to the query on a scale of 0.0 to 10.0.\n\nQuery: "${question}"\n\nDocument: "...${textPreview}..."\n\nScoring Criteria:\n- 10: Contains the exact answer/fact requested.\n- 5-9: Discusses the topic closely but might miss specific details.\n- 0-4: Tangentially related or irrelevant.\n\nOutput: Return ONLY the number (e.g., 8.5). No explanation.`;

  try {
    const response = await httpRequest({
      method: 'POST',
      url: `${OLLAMA_URL}/api/chat`,
      body: { model: MODEL_NAME, messages: [{ role: 'user', content: prompt }], stream: false, think: false, options: { temperature: 0, num_predict: 10 } },
      json: true
    });
    const content = response?.message?.content || '0';
    const match = content.match(/[\d]+(\.[\d]+)?/);
    const score = match ? parseFloat(match[0]) : 0;
    return { ...doc, reranker_score: score, final_score: (score * 0.9) + ((doc.keyword_score || 0) * 0.1) };
  } catch (error) {
    return { ...doc, reranker_score: 0, final_score: (doc.keyword_score || 0), error: error.message };
  }
});

const results = await Promise.all(scorePromises);
const topResults = results.filter(r => r.reranker_score >= MIN_SCORE).sort((a, b) => b.final_score - a.final_score).slice(0, TOP_K);

return [{ json: { ...inputData, top_results: topResults }}];

const inputData = $input.first().json;
const config = inputData.config;
const question = inputData.question;
const results = inputData.top_results;
const chatHistory = inputData.chat_history || [];

// Build context with clean source format
const contextBlocks = results.map((r, i) => {
  const docTitle = r.title || 'Unknown Document';
  const pageNum = r.page_num || 1;
  const contextText = r.context_text || r.text || '';

  return `--- Source: ${docTitle}, Page ${pageNum} ---\n${contextText}`;
}).join('\n\n');

const systemPrompt = `You are Mattervault, a legal document assistant for a law firm specializing in estate planning.\n\nYOUR ROLE: Answer questions ONLY using the provided document excerpts. You report what documents say — you do not provide legal advice.\n\nSTRICT RULES:\n1. ONLY use information from the Context Documents provided below. Never use outside knowledge.\n2. If the answer is not in the provided documents, say: "I don't find that information in the available documents for this matter."\n3. NEVER fabricate, speculate, or infer beyond what the documents explicitly state.\n4. For EVERY claim, cite the source using EXACTLY this format: (Source: [Document Title], Page [N])\n5. Be THOROUGH — include ALL relevant information from the context, not just the first match.\n6. Consider the FULL picture — if asked about marriages, also mention divorces/separations if present.\n7. If a question is unrelated to the documents (general knowledge, opinions, etc.), decline: "I can only answer questions about documents in this matter."\n8. For legal terms, quote the exact document language in quotation marks.\n9. If documents contain conflicting information, note the conflict and cite both sources.\n10. Do NOT use numbered source references like "Source 1" — always use the full document name.\n11. You may reference previous conversation for context, but ALL facts MUST come from the documents.\n12. Never provide legal advice or opinions — only report what the documents state.\n\nRESPONSE FORMAT:\n- Lead with the direct answer to the question\n- Support with specific citations from the documents\n- Keep responses concise and professional\n- Use quotation marks when citing exact document language`;

// Build messages array with chat history
const messages = [
  { role: 'system', content: systemPrompt }
];

// Add chat history (previous Q&A pairs)
for (const msg of chatHistory) {
  messages.push({
    role: msg.role === 'assistant' ? 'assistant' : 'user',
    content: msg.content
  });
}

// Add current user question with document context
const userPrompt = `Context Documents:\n${contextBlocks}\n\n---\n\nQuestion: ${question}\n\nAnswer based ONLY on the context documents above. Cite each fact with (Source: [Document Title], Page [N]).`;
messages.push({ role: 'user', content: userPrompt });

// V5: Pass through all inputData fields for persistence/audit, plus messages and sources
return [{
  json: {
    ...inputData,
    messages: messages,
    sources: results.map(r => ({
      title: r.title || 'Unknown',
      page: r.page_num || 1,
      document_id: r.payload?.document_id || null
    }))
  }
}];

const response = $input.first().json;
const promptData = $('Build LLM Prompt').first().json;
const allSources = promptData.sources;

let answer = '';
if (response.message && response.message.content) {
  answer = response.message.content;
} else if (response.response) {
  answer = response.response;
} else {
  answer = 'I encountered an issue generating a response. Please try again.';
}

const citationRegex = /\(Source:\s*([^,]+),\s*Page\s*(\d+)\)/gi;
const citedSources = new Map();
let match;
while ((match = citationRegex.exec(answer)) !== null) {
  const title = match[1].trim();
  const page = parseInt(match[2]);
  if (!citedSources.has(title)) citedSources.set(title, new Set());
  citedSources.get(title).add(page);
}

let citations;
if (citedSources.size > 0) {
  const uniqueDocs = Array.from(citedSources.keys());
  citations = uniqueDocs.map(title => {
    const pages = Array.from(citedSources.get(title)).sort((a,b) => a-b);
    const source = allSources.find(s => s.title === title);
    return { source: title, pages, document_id: source?.document_id || null };
  });
} else {
  const uniqueTitles = [...new Set(allSources.map(s => s.title))];
  citations = uniqueTitles.map(title => {
    const source = allSources.find(s => s.title === title);
    return { source: title, pages: [], document_id: source?.document_id || null };
  });
}

const citationsList = citations.map(c => `- ${c.source}`).join('\n');

return [{ json: {
  ...promptData,
  response_text: answer + '\n\n---\n**Citations:**\n' + citationsList,
  citations
}}];

