// Final output - return only what the UI needs
const data = $('Format Response').first().json;

return [{ json: {
  output: data.response_text,
  conversation_id: data.conversation_id,
  is_new_conversation: data.is_new_conversation,
  citations: data.citations,
  correlation_id: data.correlation_id,
  execution_id: $execution.id
}}];

// Final output for no-results case
const data = $('No Results Response').first().json;

return [{ json: {
  output: data.response_text,
  conversation_id: data.conversation_id,
  is_new_conversation: data.is_new_conversation,
  citations: [],
  correlation_id: data.correlation_id,
  execution_id: $execution.id
}}];
